module counter_2bit(
    input clk, rst, up_dn,
    output reg [1:0] q);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst)
            q <= 2'b0;
        else if (up_dn)
            q <= q + 1;
        else
            q <= q - 1;
    end
endmodule
